 36→public class ParameterListWrappingRule :
 37→    StandardRule(
 38→        id = "parameter-list-wrapping",
 39→        usesEditorConfigProperties = setOf(
 40→            CODE_STYLE_PROPERTY,
 41→            INDENT_SIZE_PROPERTY,
 42→            INDENT_STYLE_PROPERTY,
 43→            MAX_LINE_LENGTH_PROPERTY,
 44→        ),
 45→    ) {
 46→    private var codeStyle = CODE_STYLE_PROPERTY.defaultValue
 47→    private var indentConfig = IndentConfig.DEFAULT_INDENT_CONFIG
 48→    private var maxLineLength = MAX_LINE_LENGTH_PROPERTY.defaultValue
 49→
 50→    override fun beforeFirstNode(editorConfig: EditorConfig) {
 51→        codeStyle = editorConfig[CODE_STYLE_PROPERTY]
 52→        maxLineLength = editorConfig[MAX_LINE_LENGTH_PROPERTY]
 53→        indentConfig = IndentConfig(
 54→            indentStyle = editorConfig[INDENT_STYLE_PROPERTY],
 55→            tabWidth = editorConfig[INDENT_SIZE_PROPERTY],
 56→        )
 57→        if (indentConfig.disabled) {
 58→            stopTraversalOfAST()
 59→        }
 60→    }
 61→
 62→    override fun beforeVisitChildNodes(
 63→        node: ASTNode,
 64→        autoCorrect: Boolean,
 65→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 66→    ) {
 67→        when (node.elementType) {
 68→            NULLABLE_TYPE -> wrapNullableType(node, emit, autoCorrect)
 69→            VALUE_PARAMETER_LIST -> {
 70→                if (node.needToWrapParameterList()) {
 71→                    wrapParameterList(node, emit, autoCorrect)
 72→                }
 73→            }
 74→        }
 75→    }
 76→
 77→    private fun wrapNullableType(
 78→        node: ASTNode,
 79→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
 80→        autoCorrect: Boolean,
 81→    ) {
 82→        require(node.elementType == NULLABLE_TYPE)
 83→        node
 84→            .takeUnless {
 85→                // skip when max line length is not exceedd
 86→                (node.column - 1 + node.textLength) <= maxLineLength
 87→            }?.findChildByType(FUNCTION_TYPE)
 88→            ?.findChildByType(VALUE_PARAMETER_LIST)
 89→            ?.takeIf { it.findChildByType(VALUE_PARAMETER) != null }
 90→            ?.takeUnless { it.textContains('\n') }
 91→            ?.let {
 92→                node
 93→                    .children()
 94→                    .forEach {
 95→                        when (it.elementType) {
 96→                            LPAR -> {
 97→                                emit(
 98→                                    it.startOffset,
 99→                                    "Parameter of nullable type should be on a separate line (unless the type fits on a single line)",
100→                                    true,
101→                                )
102→                                if (autoCorrect) {
103→                                    it.upsertWhitespaceAfterMe("\n${indentConfig.indent}")
104→                                }
105→                            }
106→                            RPAR -> {
107→                                emit(it.startOffset, errorMessage(it), true)
108→                                if (autoCorrect) {
109→                                    it.upsertWhitespaceBeforeMe("\n")
110→                                }
111→                            }
112→                        }
113→                    }
114→            }
115→    }
116→
117→    private fun ASTNode.needToWrapParameterList() =
118→        if (hasNoParameters() ||
119→            isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle() ||
120→            isFunctionTypeWrappedInNullableType()
121→        ) {
122→            false
123→        } else {
124→            // each parameter should be on a separate line if
125→            // - at least one of the parameters is
126→            // - maxLineLength exceeded (and separating parameters with \n would actually help)
127→            // in addition, "(" and ")" must be on separates line if any of the parameters are (otherwise on the same)
128→            textContains('\n') || this.exceedsMaxLineLength()
129→        }
130→
131→    private fun ASTNode.hasNoParameters(): Boolean {
132→        require(elementType == VALUE_PARAMETER_LIST)
133→        return firstChildNode?.treeNext?.elementType == RPAR
134→    }
135→
136→    private fun ASTNode.isPartOfFunctionLiteralInNonKtlintOfficialCodeStyle(): Boolean {
137→        require(elementType == VALUE_PARAMETER_LIST)
138→        return codeStyle != ktlint_official && treeParent?.elementType == FUNCTION_LITERAL
139→    }
140→
141→    private fun ASTNode.isFunctionTypeWrappedInNullableType(): Boolean {
142→        require(elementType == VALUE_PARAMETER_LIST)
143→        return treeParent.elementType == FUNCTION_TYPE && treeParent?.treeParent?.elementType == NULLABLE_TYPE
144→    }
145→
146→    private fun wrapParameterList(
147→        node: ASTNode,
148→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
149→        autoCorrect: Boolean,
150→    ) {
151→        val newIndentLevel = getNewIndentLevel(node)
152→        node
153→            .children()
154→            .forEach { child -> wrapParemeterInList(newIndentLevel, child, emit, autoCorrect) }
155→    }
156→
157→    private fun getNewIndentLevel(node: ASTNode): Int {
158→        val currentIndentLevel = indentConfig.indentLevelFrom(node.lineIndent())
159→        return when {
160→            // IDEA quirk:
161→            // fun <
162→            //     T,
163→            //     R> test(
164→            //     param1: T
165→            //     param2: R
166→            // )
167→            // instead of
168→            // fun <
169→            //     T,
170→            //     R> test(
171→            //         param1: T
172→            //         param2: R
173→            //     )
174→            currentIndentLevel > 0 && node.hasTypeParameterListInFront() -> currentIndentLevel - 1
175→
176→            else -> currentIndentLevel
177→        }
178→    }
179→
180→    private fun wrapParemeterInList(
181→        newIndentLevel: Int,
182→        child: ASTNode,
183→        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
184→        autoCorrect: Boolean,
185→    ) {
186→        val indent = "\n" + indentConfig.indent.repeat(newIndentLevel)
187→        when (child.elementType) {
188→            LPAR -> {
189→                val prevLeaf = child.prevLeaf()
190→                if (prevLeaf is PsiWhiteSpace && prevLeaf.textContains('\n')) {
191→                    emit(child.startOffset, errorMessage(child), true)
192→                    if (autoCorrect) {
193→                        prevLeaf.delete()
194→                    }
195→                }
196→            }
197→            VALUE_PARAMETER,
198→            RPAR,
199→            -> {
200→                // aiming for
201→                // ... LPAR
202→                // <line indent + indentSize> VALUE_PARAMETER...
203→                // <line indent> RPAR
204→                val intendedIndent = if (child.elementType == VALUE_PARAMETER) {
205→                    indent + indentConfig.indent
206→                } else {
207→                    indent
208→                }
209→
210→                val prevLeaf = child.prevLeaf()
211→                if (prevLeaf is PsiWhiteSpace) {
212→                    if (prevLeaf.getText().contains("\n")) {
213→                        // The current child is already wrapped to a new line. Checking and fixing the
214→                        // correct size of the indent is the responsibility of the IndentationRule.
215→                        return
216→                    } else {
217→                        // The current child needs to be wrapped to a newline.
218→                        emit(child.startOffset, errorMessage(child), true)
219→                        if (autoCorrect) {
220→                            // The indentation is purely based on the previous leaf only. Note that in
221→                            // autoCorrect mode the indent rule, if enabled, runs after this rule and
222→                            // determines the final indentation. But if the indent rule is disabled then the
223→                            // indent of this rule is kept.
224→                            (prevLeaf as LeafPsiElement).rawReplaceWithText(intendedIndent)
225→                        }
226→                    }
227→                } else {
228→                    // Insert a new whitespace element in order to wrap the current child to a new line.
229→                    emit(child.startOffset, errorMessage(child), true)
230→                    if (autoCorrect) {
231→                        child.treeParent.addChild(PsiWhiteSpaceImpl(intendedIndent), child)
232→                    }
233→                }
234→                // Indentation of child nodes need to be fixed by the IndentationRule.
235→            }
236→        }
237→    }
238→
239→    private fun ASTNode.exceedsMaxLineLength() = (column - 1 + textLength) > maxLineLength && !textContains('\n')
240→
241→    private fun errorMessage(node: ASTNode) =
242→        when (node.elementType) {
243→            LPAR -> """Unnecessary newline before "(""""
244→            VALUE_PARAMETER ->
245→                "Parameter should be on a separate line (unless all parameters can fit a single line)"
246→            RPAR -> """Missing newline before ")""""
247→            else -> throw UnsupportedOperationException()
248→        }
249→
250→    private fun ASTNode.hasTypeParameterListInFront(): Boolean {
251→        val parent = this.treeParent
252→        val typeParameterList = if (parent.elementType == PRIMARY_CONSTRUCTOR) {
253→            parent.prevSibling { it.elementType == TYPE_PARAMETER_LIST }
254→        } else {
255→            parent.children().firstOrNull { it.elementType == TYPE_PARAMETER_LIST }
256→        }
257→        val typeListNode = typeParameterList
258→            ?: parent.psi.collectDescendantsOfType<KtTypeArgumentList>().firstOrNull()?.node
259→            ?: return false
260→        return typeListNode.children().any { it.isWhiteSpaceWithNewline() }
261→    }
262→}
