    private fun wouldExceedMaxLineLength(colonNode: ASTNode): Boolean {
        require(colonNode.elementType == COLON)

        // Find the start of the function line to calculate total length
        val functionNode = colonNode.treeParent
        val returnTypeNode = colonNode.nextLeaf()?.nextLeaf() // Skip whitespace to get to return type

