        // We need to find the function start column and add the length until the end of return type
        val functionStartColumn = functionNode.column - 1
        val colonEndOffset = colonNode.startOffset + colonNode.textLength - functionNode.startOffset
        val returnTypeLength = returnTypeNode.textLength

        // Total length would be: function start column + position of colon + ": " + return type length
        val totalLength = functionStartColumn + colonEndOffset + 2 + returnTypeLength

